mapper.select:
SELECT a.id, a.station_id, s.name AS station_name, a.event_time, a.level, a.level_label, a.device_name, a.alarm_type, a.description, a.status, a.owner, a.suggestion FROM dashboard_alarm_snapshot a JOIN dashboard_station s ON s.id = a.station_id
AND a.level = #{level}
AND a.station_id = #{stationId}
ORDER BY a.event_time DESC, a.id DESC
